  announcements: [],
  messages: []
};

function App() {
  const [state, setState] = useState(initialState);
  const [currentRole, setCurrentRole] = useState('Super Admin');
  const [activeAction, setActiveAction] = useState(roleOptions['Super Admin'][0].action);
  const [activePublicPage, setActivePublicPage] = useState('Home');
  const [user, setUser] = useState(null);
  const [authError, setAuthError] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState(null);
  const [publicLoginRole, setPublicLoginRole] = useState(null);

  const openRoleLogin = (role) => {
    setPublicLoginRole(role);
    setActivePublicPage('Login');
  };

  const renderPublicPage = (page) => {
    switch (page) {
      case 'Home':
        return <HomePage state={state} openRoleLogin={openRoleLogin} />;
      case 'About':
        return <AboutSchool />;
      case 'Admissions':
        return <AdmissionsPage state={state} />;
      case 'Academics':
        return <AcademicsPage />;
      case 'Gallery':
        return <GalleryPage />;
      case 'Announcements':
        return <AnnouncementsPage state={state} />;
      case 'Contact':
        return <ContactPage />;
      case 'Login':
        return <RoleLoginPage role={publicLoginRole} setPublicLoginRole={setPublicLoginRole} onSubmit={handleLogin} authError={authError} />;
      default:
        return <HomePage state={state} openRoleLogin={openRoleLogin} />;
    }
  };

  useEffect(() => {
    if (!user) return;
    const fetchData = async () => {
      try {
        const [schoolsRes, studentsRes, teachersRes] = await Promise.all([
          axios.get('/api/schools'),
          axios.get('/api/students'),
          axios.get('/api/teachers')
        ]);
        setState(prev => ({
          ...prev,
          schools: schoolsRes.data.length ? schoolsRes.data : prev.schools,
          students: studentsRes.data.length ? studentsRes.data : prev.students,
          teachers: teachersRes.data.length ? teachersRes.data : prev.teachers
        }));
      } catch (error) {
        console.error('Failed to load backend data:', error);
      }
    };
    fetchData();
  }, [user]);

  const selectedStudents = useMemo(() => state.students.filter(student => student.grade === '5'), [state.students]);

  const handleLogin = async (event) => {
    event.preventDefault();
    setAuthError('');
    const form = event.target;
    const identifier = form.loginEmail.value;
    const password = form.loginPassword.value;
    const requestedRole = normalizeRole(form.loginRole?.value || publicLoginRole || 'Super Admin');

    try {
      const response = await axios.post('/api/auth/login', { identifier, password });
      const token = response.data.token;
      const role = normalizeRole(response.data.role);
      if (publicLoginRole && role !== publicLoginRole) {
        setAuthError(`Please login with ${publicLoginRole} credentials.`);
        return;
      }
      if (!publicLoginRole && requestedRole && role !== requestedRole) {
        setAuthError(`The credentials provided do not match ${requestedRole}.`);
        return;
      }
      setUser({ email: identifier, role, userId: response.data.userId, token });
      axios.defaults.headers.common.Authorization = `Bearer ${token}`;
      setCurrentRole(role);
      setActiveAction(roleOptions[role]?.[0]?.action || 'renderStudentRecords');
      setPublicLoginRole(null);
      form.reset();
    } catch (err) {
      console.error('Login failed', err);
      setAuthError(err.response?.data?.error || 'Login failed.');
    }
  };

  const handleSignUp = async (event) => {
    event.preventDefault();
    setAuthError('');
    const form = event.target;
    const email = form.signupEmail.value;
    const password = form.signupPassword.value;
    const role = normalizeRole(form.signupRole.value);

    try {
      const response = await axios.post('/api/auth/register', { email, password, role });
      const token = response.data.token;
      setUser({ email, role, userId: response.data.userId, token });
      axios.defaults.headers.common.Authorization = `Bearer ${token}`;
      setCurrentRole(role);
      setActiveAction(roleOptions[role]?.[0]?.action || roleOptions['Super Admin'][0].action);
      form.reset();
    } catch (err) {
      console.error('Sign up failed', err);
      setAuthError(err.response?.data?.error || 'Sign up failed.');
    }
  };

  const handleLogout = () => {
    setUser(null);
    delete axios.defaults.headers.common.Authorization;
    setAuthError('');
    setCurrentRole('Super Admin');
    setActiveAction(roleOptions['Super Admin'][0].action);
    setSearchQuery('');
    setSearchResults(null);
  };

  const performSearch = (query) => {
    const normalized = query.trim().toLowerCase();
    if (!normalized) {
      setSearchResults(null);
      return;
    }

    const studentMatches = state.students.filter(student => {
      return [
        student.name,
        student.admissionNumber,
        student.grade,
        student.section,
        student.email,
        student.parent?.name,
        student.parent?.contact
      ].some(value => value && value.toString().toLowerCase().includes(normalized));
    }).map(student => ({ type: 'student', ...student }));

    const teacherMatches = state.teachers.filter(teacher => {
      return [
        teacher.name,
        teacher.employeeId,
        teacher.email,
        teacher.leaveStatus,
        teacher.assignedClasses?.join(' '),
        teacher.subjects?.join(' ')
      ].some(value => value && value.toString().toLowerCase().includes(normalized));
    }).map(teacher => ({ type: 'teacher', ...teacher }));

    setSearchResults([...studentMatches, ...teacherMatches]);
  };

  const handleSearchSubmit = (event) => {
    event.preventDefault();
    performSearch(searchQuery);
  };

  const clearSearch = () => {
    setSearchQuery('');
    setSearchResults(null);
  };

  const renderWorkspace = () => {
    switch (activeAction) {
      case 'renderCreateSchools':
        return <CreateSchools state={state} setState={setState} />;
      case 'renderCreatePrincipals':
        return <CreatePrincipals state={state} setState={setState} />;
      case 'renderCreateAdmins':
        return <CreateAdmins state={state} setState={setState} />;
      case 'renderCreateAccountants':
        return <CreateAccountants state={state} setState={setState} />;
      case 'renderCreateVicePrincipals':
        return <CreateVicePrincipals state={state} setState={setState} />;
      case 'renderRegisterStudents':
        return <RegisterStudents state={state} setState={setState} />;
      case 'renderRegisterTeachers':
        return <RegisterTeachers state={state} setState={setState} />;
      case 'renderManageSubscriptions':
        return <ManageSubscriptions state={state} setState={setState} />;
      case 'renderViewTotalStudents':
        return <ViewTotalStudents state={state} />;
      case 'renderViewTotalTeachers':
        return <ViewTotalTeachers state={state} />;
      case 'renderViewRevenueReports':
        return <ViewRevenueReports state={state} />;
      case 'renderSystemSettings':
        return <SystemSettings setState={setState} />;
      case 'renderBackupRestore':
        return <BackupRestore state={state} setState={setState} />;
      case 'renderAuditLogs':
        return <AuditLogs state={state} />;
      case 'renderApproveAdmissions':
        return <ApproveAdmissions state={state} setState={setState} user={user} />;
      case 'renderManageTeachers':
        return <ManageTeachers state={state} setState={setState} />;
      case 'renderCreateTeachers':
        return <CreateTeachers state={state} setState={setState} />;
      case 'renderCreateStudents':
        return <CreateStudents state={state} setState={setState} />;
      case 'renderCreateParents':
        return <CreateParents state={state} setState={setState} />;
      case 'renderManageClasses':
        return <ManageClasses />;
      case 'renderAssignClassTeachers':
        return <AssignClassTeachers state={state} setState={setState} />;
      case 'renderGenerateReports':
        return <GenerateReports state={state} setState={setState} />;
      case 'renderSendAnnouncements':
        return <SendAnnouncements state={state} setState={setState} />;
      case 'renderApproveLeaveRequests':
        return <ApproveLeaveRequests state={state} setState={setState} />;
      case 'renderMonitorAttendance':
        return <MonitorAttendance />;
      case 'renderCheckTeacherPerformance':
        return <CheckTeacherPerformance state={state} />;
      case 'renderHandleDisciplineCases':
        return <HandleDisciplineCases />;
      case 'renderScheduleExams':
        return <ScheduleExams state={state} setState={setState} />;
      case 'renderReviewAcademicReports':
        return <ReviewAcademicReports state={state} />;
      case 'renderStudentRecords':
        return <StudentRecords state={state} />;
      case 'renderStaffRecords':
        return <StaffRecords state={state} />;
      case 'renderTransportManagement':
        return <TransportManagement />;
      case 'renderHostelManagement':
        return <HostelManagement />;
      case 'renderInventoryManagement':
        return <InventoryManagement />;
      case 'renderCertificateGeneration':
        return <CertificateGeneration state={state} />;
      case 'renderMarkAttendance':
        return <MarkAttendance state={state} setState={setState} />;
      case 'renderEnterMarks':
        return <EnterMarks state={state} setState={setState} />;
      case 'renderUploadAssignments':
        return <UploadAssignments state={state} setState={setState} />;
      case 'renderCreateExams':
        return <CreateExams state={state} setState={setState} />;
      case 'renderCommunicateWithParents':
        return <CommunicateWithParents state={state} setState={setState} />;
      case 'renderTrackStudentProgress':
        return <TrackStudentProgress state={state} />;
      case 'renderViewStudentAttendance':
        return <ViewStudentAttendance state={state} />;
      case 'renderViewStudentMarks':
        return <ViewStudentMarks state={state} />;
      case 'renderViewStudentTimetable':
        return <ViewStudentTimetable />;
      case 'renderDownloadMaterials':
        return <DownloadMaterials />;
      case 'renderSubmitAssignments':
        return <SubmitAssignments setState={setState} />;
      case 'renderPayStudentFees':
        return user?.role === 'Student' ? <PayStudentFees state={state} setState={setState} user={user} /> : <ProtectedRouteNotice role="Student" />;
      case 'renderViewStudentNotifications':
        return <ViewStudentNotifications state={state} />;
      case 'renderMonitorChildProgress':
        return <MonitorChildProgress state={state} />;
      case 'renderViewChildAttendance':
        return <ViewChildAttendance state={state} />;
      case 'renderPayChildFees':
        return user?.role === 'Parent' ? <PayChildFees state={state} setState={setState} user={user} /> : <ProtectedRouteNotice role="Parent" />;
      case 'renderChatWithTeachers':
        return <ChatWithTeachers state={state} />;
      case 'renderDownloadReportCards':
        return <DownloadReportCards state={state} />;
      case 'renderFeeCollection':
        return <FeeCollection state={state} setState={setState} />;
      case 'renderSalaryManagement':
        return <SalaryManagement state={state} />;
      case 'renderExpenseTracking':
        return <ExpenseTracking state={state} setState={setState} />;
      case 'renderFinancialReports':
        return <FinancialReports state={state} />;
      case 'renderTaxReports':
        return <TaxReports state={state} />;
      default:
        return <div className="rounded-3xl bg-white p-8 shadow-sm border border-slate-200">Select an option from the sidebar.</div>;
    }
  };

  if (!user) {
    return (
      <div className="app-shell public-shell">
        <header className="topbar public-topbar">
          <div className="brand-block">
            <div className="brand-name">Evergreen School ERP</div>
            <div className="brand-tag">Professional school ERP for modern education institutions</div>
          </div>
          <nav className="public-nav">
            {publicPages.map(page => (
              <button
                key={page.key}
                className={page.key === activePublicPage ? 'nav-button active' : 'nav-button'}
                onClick={() => setActivePublicPage(page.key)}
              >
                {page.label}
              </button>
            ))}
          </nav>
        </header>
        <main className="public-grid public-grid-single">
          <section className="public-content full-width">
            {renderPublicPage(activePublicPage)}
          </section>
        </main>
      </div>
    );
  }

  const roleClass = `role-${currentRole.replace(/\s+/g, '-')}`;
  return (
    <div className={`app-shell ${roleClass}`}>
        <header className="topbar">
          <div>
            <h1>School Management System</h1>
            <p>Modern functional SPA scaffold for MERN development.</p>
          </div>
          <div className="topbar-controls">
            <form className="search-bar" onSubmit={handleSearchSubmit}>
              <input
                type="search"
                value={searchQuery}
                onChange={event => setSearchQuery(event.target.value)}
                placeholder="Search students or teachers (name, admission no, or employee ID)"
                aria-label="Search students or teachers by name, admission number, or employee ID"
                title="Search students or teachers by name, admission number, or employee ID"
              />
              <button type="submit">Search</button>
              {searchResults !== null && <button type="button" onClick={clearSearch}>Clear</button>}
            </form>
            <div className="user-badge">Signed in as {user.email} ({user.role})</div>
            <div className="role-label">Current dashboard: {currentRole}</div>
            <button className="secondary-button" onClick={handleLogout}>Logout</button>
            <div className="notification-badge">{state.notifications.length}</div>
          </div>
        </header>
      <div className="main-grid">
        <aside className="sidebar">
          <div className="sidebar-title">{currentRole} Options</div>
          <div className="sidebar-actions">
            {(roleOptions[currentRole] || roleOptions['Super Admin']).map(option => (
              <button
                key={option.action}
                className={option.action === activeAction ? 'active' : ''}
                onClick={() => setActiveAction(option.action)}
              >
                {option.label}
              </button>
            ))}
          </div>
        </aside>
        <main className="workspace">
          {searchResults !== null && <SearchResults results={searchResults} query={searchQuery} />}
          {renderWorkspace()}
        </main>
        <aside className="notifications-panel">
          <div className="panel-header">
            <div>Real-Time Notifications</div>
            <button onClick={() => setState(prev => ({ ...prev, notifications: [] }))}>Clear</button>
          </div>
          <div className="notifications-list">
            {state.notifications.length === 0 ? (
              <div className="empty-state">No notifications yet.</div>
            ) : state.notifications.map(item => (
              <div key={item.id} className="notification-card">
                <div>{item.message}</div>
                <div className="notification-meta">Channels: {item.channels.join(', ')}</div>
                <div className="notification-time">{item.time}</div>
              </div>
            ))}
          </div>
        </aside>
      </div>
    </div>
  );
}

function panelWrapper(title, description, children) {
  return (
    <div className="panel-card">
      <div className="panel-hero">
        <div className="panel-hero-copy">
          <h2>{title}</h2>
          <p>{description}</p>
        </div>
        <div className="panel-hero-image" style={{ backgroundImage: `linear-gradient(180deg, rgba(15, 23, 42, 0.24), rgba(15, 23, 42, 0.04)), url(${getPanelHeroImage(title)})` }} />
      </div>
      {children}
    </div>
  );
}

function SearchResults({ results, query }) {
  return (
    <div className="panel-card search-results-card">
      <div className="panel-hero-copy">
        <h2>Search Results</h2>
        <p>Showing matched student and teacher records for &ldquo;{query}&rdquo;.</p>
      </div>
      {results.length === 0 ? (
        <div className="empty-state">No matching students or teachers were found.</div>
      ) : (
        <div className="search-results-grid">
          {results.map(result => result.type === 'student' ? (
            <div key={result.admissionNumber} className="search-result-card">
              <div className="result-type">Student</div>
              <div className="result-row"><strong>Name:</strong> {result.name}</div>
              <div className="result-row"><strong>Admission No.:</strong> {result.admissionNumber}</div>
              <div className="result-row"><strong>Grade:</strong> {result.grade}{result.section}</div>
              <div className="result-row"><strong>Parent:</strong> {result.parent?.name}</div>
              <div className="result-row"><strong>Status:</strong> {result.status}</div>
            </div>
          ) : (
            <div key={result.employeeId} className="search-result-card">
              <div className="result-type">Teacher</div>
              <div className="result-row"><strong>Name:</strong> {result.name}</div>
              <div className="result-row"><strong>Employee ID:</strong> {result.employeeId}</div>
              <div className="result-row"><strong>Subjects:</strong> {result.subjects?.join(', ')}</div>
              <div className="result-row"><strong>Assigned Classes:</strong> {result.assignedClasses?.join(', ')}</div>
              <div className="result-row"><strong>Status:</strong> {result.leaveStatus || 'Active'}</div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function ProtectedRouteNotice({ role }) {
  return panelWrapper('Access Restricted', `Only ${role} users may access this dashboard.`, (
    <div className="empty-state">Please sign in as a {role} to continue.</div>
  ));
}

function CreateSchools({ state, setState }) {
  const handleSubmit = (event) => {
    event.preventDefault();
    const form = event.target;
    const school = {
      id: `SCH${Math.floor(100 + Math.random() * 900)}`,
      name: form.schoolName.value,
      location: form.schoolLocation.value,
      board: form.schoolBoard.value,
      licenseKey: form.schoolLicense.value,
      status: 'Active',
      tier: form.schoolTier.value
    };
    (async () => {
      try {
        const res = await axios.post('/api/schools', school);
        const saved = { ...res.data, id: res.data.id || res.data._id };
        setState(prev => ({ ...prev, schools: [...prev.schools, saved], notifications: [{ id: Date.now(), message: `[Super Admin created school] ${saved.name} enrolled.`, channels: ['Admin', 'Accountant'], time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }, ...prev.notifications] }));
        form.reset();
      } catch (err) {
        console.error('Create school failed', err);
        alert('Failed to create school (check server).');
      }
    })();
  };

  return panelWrapper('Create Schools', 'Displays a form to input School Name, Location, Board, and License Key.', (
    <form className="grid-form" onSubmit={handleSubmit}>
      <label>
        School Name
        <input name="schoolName" required placeholder="Sunrise Academy" />
      </label>
      <label>
        Location
        <input name="schoolLocation" required placeholder="Downtown" />
      </label>
      <label>
        Board
        <select name="schoolBoard">
          <option>CBSE</option>
          <option>ICSE</option>
          <option>State Board</option>
          <option>IB</option>
        </select>
      </label>
      <label>
        License Key
        <input name="schoolLicense" required placeholder="LIC-1234" />
      </label>
      <label>
        Subscription Tier
        <select name="schoolTier">
          <option>Basic</option>
          <option>Premium</option>
          <option>Enterprise</option>
        </select>
      </label>
      <div className="form-actions"><button type="submit">Add New School</button></div>
    </form>
  ));
}

function CreatePrincipals({ state, setState }) {
  const handleSubmit = (event) => {
    event.preventDefault();
    const form = event.target;
    const principal = {
      id: `PRN${Math.floor(100 + Math.random() * 900)}`,
      name: form.principalName.value,
      email: form.principalEmail.value,
      schoolId: form.principalSchool.value
    };
    (async () => {
      try {
        await axios.post('/api/auth/register', { email: principal.email, password: form.principalKey.value, role: 'Principal' });
        setState(prev => ({ ...prev, principals: [...(prev.principals || []), principal], notifications: [{ id: Date.now(), message: `[Super Admin created principal] ${principal.name} assigned to school ${principal.schoolId}.`, channels: ['Admin'], time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }, ...prev.notifications] }));
        alert('Principal registered successfully.');
        form.reset();
      } catch (err) {
        console.error('Create principal failed', err);
        alert('Failed to create principal (check server).');
      }
    })();
  };

  return panelWrapper('Create Principals', 'A creation pipeline form to link a master principal login credential to an active registered school.', (
    <form className="grid-form" onSubmit={handleSubmit}>
      <label>
        Principal Name
        <input name="principalName" required placeholder="Anita Desai" />
      </label>
      <label>
        Email
        <input name="principalEmail" type="email" required placeholder="anita@school.edu" />
      </label>
      <label>
        Active School
        <select name="principalSchool">{state.schools.filter(s => s.status === 'Active').map(s => <option key={s.id} value={s.id}>{s.name}</option>)}</select>
      </label>
      <label>
        Login Key
        <input name="principalKey" required placeholder="PRN-4567" />
      </label>
      <div className="form-actions"><button type="submit">Create Principal</button></div>
    </form>
  ));
}

function CreateAdmins({ state, setState }) {
  const handleSubmit = (event) => {
    event.preventDefault();
    const form = event.target;
    const admin = {
      id: form.adminId.value,
      name: form.adminName.value,
      email: form.adminEmail.value,
