        setState(prev => ({ ...prev, admins: [...prev.admins, admin], notifications: [{ id: Date.now(), message: `[${form.adminCreatedBy?.value || 'Admin'} created admin] ${admin.name} onboarded to ${admin.department}.`, channels: ['Principal', 'Admin'], time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }, ...prev.notifications] }));
        alert('Admin registered successfully.');
        form.reset();
      } catch (err) {
        console.error('Create admin failed', err);
        alert('Failed to create admin (check server).');
      }
    })();
  };

  return panelWrapper('Create Admins', 'Form to register internal administrative staff profiles.', (
    <form className="grid-form" onSubmit={handleSubmit}>
      <label>
        Admin Name
        <input name="adminName" required placeholder="Rohan Mehta" />
      </label>
      <label>
        Email
        <input name="adminEmail" type="email" required placeholder="rohan.admin@school.edu" />
      </label>
      <label>
        Password
        <input name="adminPassword" type="password" required placeholder="Choose a password" />
      </label>
      <label>
        Department
        <input name="adminDepartment" required placeholder="Admissions" />
      </label>
      <label>
        Employee ID
        <input name="adminId" required placeholder="ADM-210" />
      </label>
      <div className="form-actions"><button type="submit">Register Admin</button></div>
    </form>
  ));
}

function CreateAccountants({ state, setState }) {
  const handleSubmit = (event) => {
    event.preventDefault();
    const form = event.target;
    const accountant = {
