function ApproveAdmissions({ state, setState, user }) {
  const [admissions, setAdmissions] = useState([]);
  const [loading, setLoading] = useState(false);

  const fetchAdmissions = async () => {
    setLoading(true);
    try {
      const res = await axios.get('/api/admissions');
      setAdmissions(res.data.filter(a => a.status === 'Pending'));
    } catch (err) {
      console.error('Failed to fetch admissions', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAdmissions();
  }, []);

  const approve = async (admissionId) => {
    const admission = admissions.find(a => a._id === admissionId);
    if (!admission) return;
    try {
      // mark admission approved on server
      await axios.put(`/api/admissions/${admissionId}`, { status: 'Approved', reviewedBy: user?.email || 'system' });

      // create student record
      const studentPayload = {
        admissionNumber: `STD${Math.floor(1000 + Math.random() * 9000)}`,
        name: admission.studentName || admission.name,
        grade: admission.grade,
        section: admission.section || '',
        parent: { name: admission.parentName || admission.parent || 'Not Available', contact: admission.parentContact || 'Not Available' },
        attendance: { present: 0, absent: 0, late: 0 },
        marks: {},
        status: 'Active'
      };
      const studentRes = await axios.post('/api/students', studentPayload);

      // update client state
      setState(prev => ({ ...prev, students: [...prev.students, studentRes.data], notifications: [{ id: Date.now(), message: `[${user?.role || 'Principal'} approved admission] ${studentRes.data.name} onboarded.`, channels: ['Admin', 'Parent', 'Accountant'], time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }, ...prev.notifications], pendingAdmissions: prev.pendingAdmissions.filter(p => p.admissionNumber !== (admission.admissionNumber || '')) }));

      // remove from local admissions list
      setAdmissions(prev => prev.filter(a => a._id !== admissionId));
    } catch (err) {
      console.error('Approve failed', err);
      alert(err.response?.data?.error || 'Failed to approve admission');
    }
  };

  const reject = async (admissionId) => {
    try {
      await axios.put(`/api/admissions/${admissionId}`, { status: 'Rejected', reviewedBy: user?.email || 'system' });
      setAdmissions(prev => prev.filter(a => a._id !== admissionId));
      setState(prev => ({ ...prev, notifications: [{ id: Date.now(), message: `[${user?.role || 'Principal'} rejected admission] Admission application declined.`, channels: ['Parent'], time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }, ...prev.notifications] }));
    } catch (err) {
      console.error('Reject failed', err);
      alert(err.response?.data?.error || 'Failed to reject admission');
    }
  };

  return panelWrapper('Approve Admissions', 'A workflow grid displaying incoming student profiles with approve/reject triggers.', (
    <div className="table-card">
      <div className="panel-subheader">{loading ? 'Loading admissions...' : `${admissions.length} pending`}</div>
      <table>
        <thead><tr><th>Applicant</th><th>Grade / Section</th><th>Parent</th><th>Submitted</th><th>Actions</th></tr></thead>
        <tbody>
          {admissions.map(admission => (
            <tr key={admission._id}>
              <td>{admission.studentName}</td>
              <td>{admission.grade}{admission.section ? ` / ${admission.section}` : ''}</td>
              <td>{admission.parentName || admission.parentEmail || '—'}</td>
              <td>{new Date(admission.submittedAt || admission.createdAt || Date.now()).toLocaleString()}</td>
              <td className="action-buttons"><button onClick={() => approve(admission._id)}>Approve</button><button onClick={() => reject(admission._id)}>Reject</button></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  ));
}

